arguments.command:
# 检查关键文件的修改时间
$files = @("AGENTS.md", "SOUL.md", "MEMORY.md", "USER.md", "TOOLS.md")
foreach ($file in $files) {
    $current = Get-Item "C:\Users\WH\.openclaw\workspace\$file" -ErrorAction SilentlyContinue
    $backup = Get-Item "C:\Users\WH\.openclaw\workspace-backup-20260304\$file" -ErrorAction SilentlyContinue

    if ($current -and $backup) {
        Write-Host "$file : Current=$($current.LastWriteTime) Backup=$($backup.LastWriteTime)"
    } elseif ($current) {
        Write-Host "$file : Current=$($current.LastWriteTime) (No backup)"
    } else {
        Write-Host "$file : Not found in current"
    }
}

# 检查备份目录中是否有这些文件的原始版本
$files = @("SOUL.md", "USER.md", "IDENTITY.md")
foreach ($file in $files) {
    $backupPath = "C:\Users\WH\.openclaw\workspace-backup-20260304\$file"
    if (Test-Path $backupPath) {
        $backup = Get-Item $backupPath
        $current = Get-Item "C:\Users\WH\.openclaw\workspace\$file"
        Write-Host "=== $file ==="
        Write-Host "备份大小: $($backup.Length) bytes"
        Write-Host "当前大小: $($current.Length) bytes"
        Write-Host "备份时间: $($backup.LastWriteTime)"
        Write-Host "当前时间: $($current.LastWriteTime)"
        Write-Host ""
    } else {
        Write-Host "$file 在备份中不存在"
    }
}

# 检查workspace-assistant目录
$files = @("SOUL.md", "USER.md", "IDENTITY.md")
foreach ($file in $files) {
    $assistantPath = "C:\Users\WH\.openclaw\workspace\workspace-assistant\$file"
    if (Test-Path $assistantPath) {
        $assistant = Get-Item $assistantPath
        $current = Get-Item "C:\Users\WH\.openclaw\workspace\$file"
        Write-Host "=== $file ==="
        Write-Host "assistant大小: $($assistant.Length) bytes"
        Write-Host "当前大小: $($current.Length) bytes"
        Write-Host "assistant时间: $($assistant.LastWriteTime)"
        Write-Host "当前时间: $($current.LastWriteTime)"

        # 检查内容是否相同
        $assistantContent = Get-Content $assistantPath -Raw
        $currentContent = Get-Content "C:\Users\WH\.openclaw\workspace\$file" -Raw
        if ($assistantContent -eq $currentContent) {
            Write-Host "内容: 相同"
        } else {
            Write-Host "内容: 不同"
        }
        Write-Host ""
    } else {
        Write-Host "$file 在workspace-assistant中不存在"
    }
}

